    // Normalizing steps (Backward Compatibility)
    const steps = sheet.steps && sheet.steps.length > 0 
      ? sheet.steps 
      : [{ 
          step: 1, 
          description: sheet.checkPointDescription || "Conduct standard inspection", 
          criteria: sheet.criteriaLimits || sheet.normalCondition || "Per Standard", 
          technique: sheet.type || "Visual" 
