                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent sm:bg-indigo-900/10 sm:group-hover:bg-transparent transition-colors"></div>
                    <div className="absolute top-3 left-3 bg-white/95 backdrop-blur-md px-2.5 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider text-slate-800 shadow-sm border border-slate-100">
