                    <button 
                      onClick={handleAddStep}
                      className="text-xs font-bold text-indigo-600 hover:text-indigo-700 flex items-center gap-1.5 px-3 py-1.5 bg-indigo-50 rounded-md border border-indigo-100 transition-colors"
