                    <th className="px-6 py-4 w-16 text-center">#</th>
                    <th className="px-6 py-4 w-[40%]">Action / Description</th>
                    <th className="px-6 py-4 w-[15%]">Method</th>
                    <th className="px-6 py-4 w-[25%]">Acceptance Criteria</th>
