  ArrowUpDown, ArrowUp, ArrowDown, Info, Zap
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  onUpdate: (newData: RCMItem[]) => void;
}

const CONSEQUENCE_LABELS: ConsequenceCategory[] = [
  'Hidden - Safety/Env', 
  'Hidden - Operational', 
  'Evident - Safety/Env', 
  'Evident - Operational',
  'Evident - Non-Operational'
];

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem; direction: 'asc' | 'desc' } | null>(null);
  const [generatingSheetId, setGeneratingSheetId] = useState<string | null>(null);
  const [selectedItemForSheet, setSelectedItemForSheet] = useState<RCMItem | null>(null);

  // Stats calculation
  const stats = useMemo(() => {
    return {
      total: data.length,
      highRisk: data.filter(i => i.criticality === 'High').length,
      redesign: data.filter(i => i.taskType === 'Redesign').length,
      avgRPN: Math.round(data.reduce((acc, curr) => acc + curr.rpn, 0) / data.length)
    };
  }, [data]);

  const sortedData = useMemo(() => {
    let items = [...data];
    if (searchTerm) {
      items = items.filter(i => 
        i.component.toLowerCase().includes(searchTerm.toLowerCase()) ||
        i.failureMode.toLowerCase().includes(searchTerm.toLowerCase()) ||
        i.maintenanceTask.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    if (sortConfig) {
      items.sort((a, b) => {
        const aVal = a[sortConfig.key];
        const bVal = b[sortConfig.key];
        if (aVal < bVal) return sortConfig.direction === 'asc' ? -1 : 1;
        if (aVal > bVal) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }
    return items;
  }, [data, searchTerm, sortConfig]);

  const handleSort = (key: keyof RCMItem) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig?.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const handleGenerateSheet = async (item: RCMItem) => {
    if (item.inspectionSheet) {
      setSelectedItemForSheet(item);
      return;
    }
    setGeneratingSheetId(item.id);
    try {
      const sheet = await generateInspectionSheet(item);
      const updatedData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(updatedData);
      setSelectedItemForSheet({ ...item, inspectionSheet: sheet });
    } catch (e) {
      console.error(e);
    } finally {
      setGeneratingSheetId(null);
    }
  };

