          <div className="mt-8 flex gap-3 p-3 bg-indigo-50 rounded-xl border border-indigo-100 items-start">
            <Info size={16} className="text-indigo-500 shrink-0 mt-0.5" />
            <p className="text-[11px] text-indigo-700 leading-tight">
