                        </td>
                        <td className="px-6 py-5 align-top">
                          {isStepEditing ? (
                            <textarea 
                              value={step.criteria} 
                              onChange={(e) => handleUpdateStepField(idx, 'criteria', e.target.value)}
                              className="w-full p-2 text-xs border border-indigo-300 rounded outline-none min-h-[60px]"
                            />
                          ) : (
