// Helper to check for human factor keywords in failure modes or effects
const isHumanFactor = (mode: string, effect: string): boolean => {
  const text = (mode + effect).toLowerCase();
  const keywords = ['human', 'operator', 'maintenance', 'induced', 'assembly', 'installation', 'mistake', 'error', 'wrong', 'misuse', 'improper', 'procedural', 'worker'];
  return keywords.some(k => text.includes(k));
};

