                            <p className="text-slate-800 font-medium text-base leading-relaxed">{step.description}</p>
                          )}
                        </td>
                        <td className="px-6 py-5 align-top">
                          {isStepEditing ? (
                            <input 
                              type="text" 
                              value={step.technique} 
                              onChange={(e) => handleUpdateStepField(idx, 'technique', e.target.value)}
