                                <>
                                  <button onClick={() => setEditingStepIdx(idx)} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-md transition-colors" title="Edit Step"><Pencil size={14} /></button>
