import { GoogleGenAI, Type, Schema } from "@google/genai";
import { RCMItem, FileData, InspectionSheet } from "../types";

// Define the expected output schema for structured JSON
const rcmSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      component: { 
        type: Type.STRING, 
        description: "The specific sub-component or part being analyzed (e.g., 'Pump Impeller', 'Mechanical Seal Face', 'Non-Drive End Bearing')." 
      },
      function: { 
        type: Type.STRING,
        description: "The primary function of the component in this context."
      },
      functionalFailure: { 
        type: Type.STRING,
        description: "How the component fails to fulfill its function."
      },
      failureMode: { 
        type: Type.STRING,
        description: "A SINGLE specific failure mode formatted strictly as '[Mechanism] due to [Cause]'. Example: 'Surface wear due to abrasion from scale'."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "The immediate effect of the failure on the system or safety."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ],
        description: "SAE JA1011 Consequence classification."
      },
      iso14224Code: {
        type: Type.STRING,
        description: "Standard failure mechanism code from ISO 14224 (e.g., 'Wear', 'Corrosion', 'Fatigue', 'Overheating', 'Leakage', 'Breakage')."
      },
      criticality: { 
        type: Type.STRING, 
        enum: ["High", "Medium", "Low"],
        description: "Qualitative risk assessment."
      },
      severity: {
        type: Type.INTEGER,
        description: "FMECA Severity Score (1-10)."
      },
      occurrence: {
        type: Type.INTEGER,
        description: "FMECA Occurrence Score (1-10)."
      },
      detection: {
        type: Type.INTEGER,
        description: "FMECA Detection Score (1-10)."
      },
      maintenanceTask: { 
        type: Type.STRING,
        description: "A SINGLE, FEASIBLE technical maintenance action. Must be specific and actionable."
      },
      interval: { 
        type: Type.STRING,
        description: "Recommended frequency of the task (e.g., 'Weekly', 'Every 2000 hours')."
      },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement'
        ],
        description: "The specific category of the maintenance strategy."
      }
    },
    required: ["component", "function", "functionalFailure", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

const inspectionSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    responsibility: { type: Type.STRING, description: "Role responsible (e.g. Operator, Mech. Tech)" },
    estimatedTime: { type: Type.STRING, description: "Total duration e.g. '30 mins'" },
    safetyPrecautions: { type: Type.STRING, description: "Required PPE only (e.g. Gloves, Goggles). Exclude LOTO/Administrative warnings." },
    toolsRequired: { type: Type.STRING, description: "List of tools, gauges, or consumables needed." },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          step: { type: Type.INTEGER },
          description: { type: Type.STRING, description: "Direct technical instruction. Start with action verb." },
          criteria: { type: Type.STRING, description: "Technical pass/fail limit or condition." },
          technique: { type: Type.STRING, description: "Method (e.g. Visual, Ultrasonic, Multimeter)" }
        },
        required: ["step", "description", "criteria", "technique"]
      }
    }
  },
  required: ["responsibility", "estimatedTime", "safetyPrecautions", "toolsRequired", "steps"]
};

export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null
): Promise<RCMItem[]> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY environment variable is not set.");
    }

    const ai = new GoogleGenAI({ apiKey });

    const parts: any[] = [];

    if (fileData) {
      parts.push({
        inlineData: {
          mimeType: fileData.mimeType,
          data: fileData.data,
        },
      });
      parts.push({
        text: "Analyze the uploaded document/image containing operational context or technical specifications."
      });
    }

    if (contextText) {
      parts.push({
        text: `Operational Context provided by user:\n${contextText}`
      });
    }

    parts.push({
      text: `Perform a DEEP, exhaustive, and highly FEASIBLE Reliability Centered Maintenance (RCM) and FMECA analysis. 

      ENGINEERING DIRECTIVES FOR MAX DETAIL & FEASIBILITY:
      1. **Component Granularity**: Break the asset down into its most basic sub-parts. For example, if it's a motor, don't just say 'Motor'; analyze 'Rotor', 'Stator Windings', 'End Shields', 'Terminal Box Connections', and 'Shaft Keyway'.
      2. **Exhaustive Failure Modes**: Aim for an exhaustive list. Each sub-component should have multiple failure modes (e.g. electrical, mechanical, environmental). 
      3. **Feasibility of Tasks**: Propose maintenance tasks that are technically feasible and follow RCM hierarchy. 
         - Prioritize **Condition Monitoring** (vibration, thermography, ultrasonic) if technically feasible.
         - Use **Lubrication** and **Servicing** for high-occurrence wear modes.
         - Use **Redesign** (Error-Proofing) specifically for human-induced failures.
      4. **Human Factors**: Explicitly identify modes caused by potential human error (e.g., 'Incorrect lubricant volume application', 'Loose terminal due to improper torque', 'Operational misalignment').
      5. **Consequence Analysis**: Use SAE JA1011 logic (Hidden/Evident).
      6. **Standardization**: Use ISO 14224 mechanism codes.

      Reproducibility: Results must be consistent and deterministic for the same context.`
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: { parts },
      config: {
        seed: 42,
        temperature: 0,
        responseMimeType: "application/json",
        responseSchema: rcmSchema,
        systemInstruction: "You are the world's most detailed Senior Reliability Engineer. You provide exhaustive RCM analyses by breaking systems down to their smallest parts and proposing highly feasible, actionable maintenance tasks. Focus on identifying and mitigating human-induced errors. Do not include markdown formatting."
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response generated from Gemini.");
    }

    const rawData = JSON.parse(text) as Omit<RCMItem, 'id' | 'rpn'>[];

    return rawData.map((item, index) => ({ 
      ...item, 
      severity: item.severity || 5,
      occurrence: item.occurrence || 3,
      detection: item.detection || 3,
      rpn: (item.severity || 5) * (item.occurrence || 3) * (item.detection || 3),
      id: `rcm-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 9)}` 
    }));

  } catch (error) {
    console.error("RCM Generation Error:", error);
    throw error;
  }
};

